    VendPackingSlipTrans        vendPackingSlipTrans    = VendPackingSlipTrans::findInventTransId_RU(this.InventTransId);

    if (!vendInvoiceTrans && !vendPackingSlipTrans)
    {
        update_recordset etgspainUnsoldInventTrans
            setting UnsoldQty = 0
            join inventTrans
                where inventTrans.RecId                     == etgspainUnsoldInventTrans.RefRecId
                join inventTransOrigin
                    where inventTransOrigin.RecId           == inventTrans.InventTransOrigin
                        && inventTransOrigin.InventTransId  == this.InventTransId;
    }
    */
    next delete(_showInfoDelReserv, _updateOrderLineOfDeliverySchedule);

